namespace HealthcareService.ServiceImplementation
{
    using HealthcareService.DataContracts;
    using HealthcareService.ServiceContracts;
    using System.Linq;

    [ServiceBehavior(InstanceContextMode = InstanceContextMode.PerCall)]
    public class PatientService : IPatientService
    {
        // In a real application, this would interact with a secure database.
        // For demonstration, we'll use a static in-memory list.
        private static List<PatientRecord> _patientRecords = new List<PatientRecord>();
        private static object _lock = new object();

        public OperationStatus SubmitPatientRecord(PatientRecord record)
        {
            if (record == null || record.Identifier == null || string.IsNullOrEmpty(record.Identifier.PatientId))
            {
                return new OperationStatus { Success = false, Message = "Invalid patient record provided." };
            }

            lock (_lock)
            {
                if (_patientRecords.Any(p => p.Identifier.PatientId == record.Identifier.PatientId))
                {
                    return new OperationStatus { Success = false, Message = $"Patient with ID {record.Identifier.PatientId} already exists." };
                }

                _patientRecords.Add(record);
                Console.WriteLine($"Received and stored patient record for ID: {record.Identifier.PatientId}");
                // In a real scenario, sensitive data would be stored encrypted at rest.
                return new OperationStatus { Success = true, Message = "Patient record submitted successfully.", RecordId = record.Identifier.PatientId };
            }
        }

        public PatientRecord GetPatientRecord(PatientIdentifier identifier)
        {
            if (identifier == null || string.IsNullOrEmpty(identifier.PatientId))
            {
                return null;
            }

            lock (_lock)
            {
                var record = _patientRecords.FirstOrDefault(p => p.Identifier.PatientId == identifier.PatientId);
                if (record != null)
                {
                    Console.WriteLine($"Retrieved patient record for ID: {record.Identifier.PatientId}");
                }
                else
                {
                    Console.WriteLine($"Patient record not found for ID: {identifier.PatientId}");
                }
                return record;
            }
        }

        public OperationStatus UpdatePatientRecord(PatientRecord record)
        {
            if (record == null || record.Identifier == null || string.IsNullOrEmpty(record.Identifier.PatientId))
            {
                return new OperationStatus { Success = false, Message = "Invalid patient record provided." };
            }

            lock (_lock)
            {
                var existingRecord = _patientRecords.FirstOrDefault(p => p.Identifier.PatientId == record.Identifier.PatientId);
                if (existingRecord == null)
                {
                    return new OperationStatus { Success = false, Message = $"Patient with ID {record.Identifier.PatientId} not found for update." };
                }

                // Update fields (example: replace the entire record for simplicity)
                _patientRecords.Remove(existingRecord);
                _patientRecords.Add(record);
                Console.WriteLine($"Updated patient record for ID: {record.Identifier.PatientId}");
                return new OperationStatus { Success = true, Message = "Patient record updated successfully.", RecordId = record.Identifier.PatientId };
            }
        }
    }
